import React from 'react';
import { ListFilter, Search, ShieldAlert, ShieldCheck, Clock } from 'lucide-react';
import clsx from 'clsx';

interface SidebarProps {
  isBlockedMode: boolean;
  setIsBlockedMode: (val: boolean) => void;
}

interface RequestEntry {
  id: string;
  endpoint: string;
  method: string;
  status: number;
  time: string;
  isBlocked?: boolean;
}

const HEALTHY_REQUESTS: RequestEntry[] = [
  { id: "req_92f3a8b2", endpoint: "/api/v1/mcp",    method: "POST", status: 200, time: "Just now" },
  { id: "req_92f3a8b1", endpoint: "/api/v1/health",  method: "GET",  status: 200, time: "2m ago" },
  { id: "req_92f3a8b0", endpoint: "/api/v1/mcp",    method: "POST", status: 200, time: "5m ago" },
  { id: "req_88a1b2c4", endpoint: "/api/v1/mcp",    method: "POST", status: 401, time: "12m ago" },
];

const BLOCKED_REQUESTS: RequestEntry[] = [
  { id: "req_alert_001", endpoint: "/api/v1/mcp",   method: "POST", status: 403, time: "Just now",  isBlocked: true },
  { id: "req_92f3a8b1",  endpoint: "/api/v1/health", method: "GET",  status: 200, time: "2m ago" },
  { id: "req_92f3a8b0",  endpoint: "/api/v1/mcp",   method: "POST", status: 200, time: "5m ago" },
  { id: "req_88a1b2c4",  endpoint: "/api/v1/mcp",   method: "POST", status: 401, time: "12m ago" },
];

export default function Sidebar({ isBlockedMode, setIsBlockedMode }: SidebarProps) {
  const [selectedId, setSelectedId] = React.useState<string>(
    isBlockedMode ? "req_alert_001" : "req_92f3a8b2"
  );

  const requests = isBlockedMode ? BLOCKED_REQUESTS : HEALTHY_REQUESTS;

  // When mode changes, auto-select the first (most recent) request
  React.useEffect(() => {
    setSelectedId(requests[0].id);
  }, [isBlockedMode]);

  return (
    <div className="w-80 border-r border-slate-800 bg-slate-900/50 flex flex-col h-full shrink-0">
      <div className="p-4 border-b border-slate-800">
        <h2 className="text-sm font-semibold text-slate-200 uppercase tracking-wider mb-4">
          Request Stream
        </h2>

        <div className="relative mb-4">
          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
          <input
            type="text"
            placeholder="Search req_id or trace_id..."
            className="w-full bg-slate-950 border border-slate-800 rounded-md py-2 pl-9 pr-4 text-sm text-slate-200 focus:outline-none focus:border-slate-600 focus:ring-1 focus:ring-slate-600 transition-all placeholder:text-slate-600"
          />
        </div>

        {/* Mode Toggle */}
        <div className="flex gap-2">
          <button
            onClick={() => setIsBlockedMode(false)}
            className={clsx(
              "flex-1 py-1.5 px-3 rounded text-xs font-medium border flex items-center justify-center gap-1.5 transition-all",
              !isBlockedMode
                ? "bg-emerald-500/10 border-emerald-500/30 text-emerald-400 shadow-sm shadow-emerald-500/10"
                : "bg-slate-800 border-slate-700 text-slate-400 hover:text-slate-300 hover:bg-slate-800/80"
            )}
          >
            <ShieldCheck className="w-3.5 h-3.5" />
            Healthy Path
          </button>
          <button
            onClick={() => setIsBlockedMode(true)}
            className={clsx(
              "flex-1 py-1.5 px-3 rounded text-xs font-medium border flex items-center justify-center gap-1.5 transition-all",
              isBlockedMode
                ? "bg-red-500/10 border-red-500/30 text-red-400 shadow-sm shadow-red-500/10"
                : "bg-slate-800 border-slate-700 text-slate-400 hover:text-slate-300 hover:bg-slate-800/80"
            )}
          >
            <ShieldAlert className="w-3.5 h-3.5" />
            Blocked Path
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto">
        <div className="flex items-center justify-between px-4 py-2 text-xs font-medium text-slate-500 border-b border-slate-800/50">
          <span>RECENT REQUESTS</span>
          <ListFilter className="w-3.5 h-3.5" />
        </div>

        {requests.map((req) => (
          <RequestItem
            key={req.id}
            {...req}
            active={selectedId === req.id}
            onClick={() => setSelectedId(req.id)}
          />
        ))}
      </div>

      {/* Selected request detail panel */}
      {selectedId && (
        <div className="border-t border-slate-800 p-4">
          <p className="text-xs font-semibold text-slate-400 uppercase mb-2">Selected Trace</p>
          <div className="bg-slate-950 rounded border border-slate-800 p-3">
            <p className="text-xs font-mono text-slate-300 break-all">{selectedId}</p>
            <div className="mt-2 flex items-center gap-2">
              {requests.find(r => r.id === selectedId)?.isBlocked ? (
                <span className="text-[10px] px-1.5 py-0.5 rounded bg-red-500/10 border border-red-500/20 text-red-400">THREAT DETECTED</span>
              ) : (
                <span className="text-[10px] px-1.5 py-0.5 rounded bg-emerald-500/10 border border-emerald-500/20 text-emerald-400">AUTHORIZED</span>
              )}
              <span className="text-[10px] text-slate-500">
                {requests.find(r => r.id === selectedId)?.endpoint}
              </span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function RequestItem({
  id, endpoint, method, status, time, active = false, isBlocked = false, onClick
}: RequestEntry & { active?: boolean; onClick?: () => void }) {
  return (
    <div
      onClick={onClick}
      className={clsx(
        "px-4 py-3 border-b border-slate-800/50 cursor-pointer transition-all group",
        active
          ? "bg-slate-800/70 border-l-2 border-l-emerald-500"
          : "hover:bg-slate-800/30 border-l-2 border-l-transparent",
        isBlocked && active && "border-l-red-500"
      )}
    >
      <div className="flex justify-between items-start mb-1.5">
        <span className="text-xs font-mono text-slate-400 group-hover:text-slate-300">{id}</span>
        <span className="flex items-center text-[10px] text-slate-500">
          <Clock className="w-3 h-3 mr-1" />
          {time}
        </span>
      </div>
      <div className="flex items-center gap-2">
        <span className={clsx(
          "text-[10px] font-bold px-1.5 py-0.5 rounded",
          method === 'GET' ? "bg-blue-500/10 text-blue-400" : "bg-purple-500/10 text-purple-400"
        )}>
          {method}
        </span>
        <span className="text-sm font-medium text-slate-200 truncate flex-1">{endpoint}</span>
        <span className={clsx(
          "text-[10px] font-mono px-1.5 py-0.5 rounded border",
          status === 200 ? "bg-emerald-500/10 border-emerald-500/20 text-emerald-400" :
          isBlocked || status === 403 ? "bg-red-500/10 border-red-500/20 text-red-400" :
          "bg-amber-500/10 border-amber-500/20 text-amber-400"
        )}>
          {status}
        </span>
      </div>
    </div>
  );
}
