import React from 'react';
import { ShieldAlert, ShieldCheck, Key, Fingerprint, Network, Server, CheckCircle2, XCircle, ChevronRight } from 'lucide-react';
import clsx from 'clsx';

interface RequestTracerProps {
  isBlockedMode: boolean;
}

export default function RequestTracer({ isBlockedMode }: RequestTracerProps) {
  
  const layers = [
    {
      id: 1,
      title: "Prompt Injection Shield",
      icon: ShieldAlert,
      description: "Inspects raw JSON-RPC payloads for jailbreaks & malicious prompts",
      latency: "14ms",
      status: isBlockedMode ? "blocked" : "passed",
      logs: isBlockedMode 
        ? "[WARN] Heuristic match found: System Prompt Override attempted in arguments." 
        : "[INFO] Payload scan clean. No heuristics matched."
    },
    {
      id: 2,
      title: "Row-Level Security (RLS) Context",
      icon: Network,
      description: "Applies tenancy and data-isolation scopes",
      latency: "4ms",
      status: isBlockedMode ? "bypassed" : "passed",
      logs: isBlockedMode 
        ? "-" 
        : "[INFO] RLS Policy 'tenant_a_strict' attached to context."
    },
    {
      id: 3,
      title: "Scope Enforcement",
      icon: Fingerprint,
      description: "Verifies OAuth scopes/permissions for requested tool",
      latency: "2ms",
      status: isBlockedMode ? "bypassed" : "passed",
      logs: isBlockedMode 
        ? "-" 
        : "[INFO] Tool 'salesforce.query' authorized for scopes [nexusmcp:read]."
    },
    {
      id: 4,
      title: "JWT Validation",
      icon: Key,
      description: "Decrypts RS256 signatures, verifies issuer and expiration",
      latency: "18ms",
      status: isBlockedMode ? "bypassed" : "passed",
      logs: isBlockedMode 
        ? "-" 
        : "[INFO] JWT Signature valid. Issuer matched. Token active."
    },
    {
      id: 5,
      title: "Request ID & Correlation",
      icon: Server,
      description: "Attaches unique request_id and tracing headers",
      latency: "1ms",
      status: isBlockedMode ? "bypassed" : "passed",
      logs: isBlockedMode 
        ? "-" 
        : "[INFO] Attached Trace ID: 8a4b... Request ID: req_92f3a8b2"
    },
    {
      id: 6,
      title: "TLS Termination",
      icon: ShieldCheck,
      description: "Final boundary checks and decryption",
      latency: "22ms",
      status: isBlockedMode ? "bypassed" : "passed",
      logs: isBlockedMode 
        ? "-" 
        : "[INFO] Connection secured via mTLS."
    }
  ];

  return (
    <div className="bg-slate-900 border border-slate-800 rounded-lg p-6 relative">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-lg font-semibold text-slate-100 flex items-center gap-2">
            Multi-Layered Request Tracer
            {isBlockedMode ? (
              <span className="px-2 py-0.5 rounded text-xs font-medium bg-red-500/10 text-red-400 border border-red-500/20">
                Threat Detected
              </span>
            ) : (
              <span className="px-2 py-0.5 rounded text-xs font-medium bg-emerald-500/10 text-emerald-400 border border-emerald-500/20">
                Authorized
              </span>
            )}
          </h2>
          <p className="text-sm text-slate-400 mt-1">
            Tracking execution path across 6 middleware layers (Last-In-First-Out)
          </p>
        </div>
        <div className="text-right">
          <div className="text-sm text-slate-400">Total Latency</div>
          <div className="text-2xl font-mono text-slate-200">
            {isBlockedMode ? "14ms" : "61ms"}
          </div>
        </div>
      </div>

      <div className="space-y-0 relative">
        {/* Vertical connecting line */}
        <div className="absolute top-4 bottom-4 left-[27px] w-0.5 bg-slate-800 z-0"></div>

        {layers.map((layer, index) => {
          const isPassed = layer.status === 'passed';
          const isBlocked = layer.status === 'blocked';
          const isBypassed = layer.status === 'bypassed';
          
          return (
            <div key={layer.id} className={clsx(
              "relative z-10 flex gap-6 p-4 rounded-lg transition-all",
              isBlocked ? "bg-red-500/5 border border-red-500/10" : 
              isPassed ? "hover:bg-slate-800/50" : "opacity-50"
            )}>
              <div className="flex flex-col items-center mt-1">
                <div className={clsx(
                  "w-6 h-6 rounded-full flex items-center justify-center ring-4 ring-slate-900",
                  isPassed ? "bg-emerald-500/20 text-emerald-400" :
                  isBlocked ? "bg-red-500/20 text-red-400" :
                  "bg-slate-800 text-slate-500"
                )}>
                  {isPassed ? <CheckCircle2 className="w-4 h-4" /> :
                   isBlocked ? <XCircle className="w-4 h-4" /> :
                   <div className="w-2 h-2 rounded-full bg-slate-600" />}
                </div>
              </div>
              
              <div className="flex-1">
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-3">
                    <div className={clsx(
                      "p-2 rounded-md",
                      isPassed ? "bg-emerald-500/10" :
                      isBlocked ? "bg-red-500/10" :
                      "bg-slate-800"
                    )}>
                      <layer.icon className={clsx(
                        "w-5 h-5",
                        isPassed ? "text-emerald-400" :
                        isBlocked ? "text-red-400" :
                        "text-slate-500"
                      )} />
                    </div>
                    <div>
                      <h4 className={clsx(
                        "text-sm font-semibold",
                        isPassed || isBlocked ? "text-slate-200" : "text-slate-500"
                      )}>
                        {layer.id}. {layer.title}
                      </h4>
                      <p className="text-xs text-slate-500 mt-0.5">{layer.description}</p>
                    </div>
                  </div>
                  
                  {!isBypassed && (
                    <div className="text-xs font-mono text-slate-500 bg-slate-950 px-2 py-1 rounded border border-slate-800">
                      {layer.latency}
                    </div>
                  )}
                </div>
                
                {!isBypassed && (
                  <div className="mt-3 pl-12">
                    <div className="bg-slate-950 rounded-md border border-slate-800 p-2.5 flex items-start gap-2">
                      <ChevronRight className="w-4 h-4 text-slate-600 mt-0.5 shrink-0" />
                      <code className={clsx(
                        "text-xs font-mono break-all",
                        isBlocked ? "text-red-400" : "text-slate-400"
                      )}>
                        {layer.logs}
                      </code>
                    </div>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
